      out.write("	<script>\n");
      out.write("/* ================= INITIAL THEME ================= */\n");
      out.write("if (localStorage.getItem(\"theme\") === \"dark\") {\n");
      out.write("    document.body.classList.add(\"dark-theme\");\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* ================= MAIN ================= */\n");
      out.write("document.addEventListener(\"DOMContentLoaded\", function () {\n");
      out.write("\n");
      out.write("    const params = new URLSearchParams(window.location.search);\n");
      out.write("    const tab = params.get(\"tab\");\n");
      out.write("    const success = params.get(\"success\");\n");
      out.write("    const error = params.get(\"error\");\n");
      out.write("\n");
      out.write("    /* -------- Restore Tab -------- */\n");
      out.write("    showSection(tab || \"selfAttendance\");\n");
      out.write("\n");
      out.write("    /* -------- SUCCESS MESSAGES -------- */\n");
      out.write("    if (success === \"Login\")\n");
      out.write("        showToast(\"Welcome! Logged in successfully\");\n");
      out.write("\n");
      out.write("    else if (success === \"MeetingScheduled\")\n");
      out.write("        showToast(\"Meeting scheduled successfully\");\n");
      out.write("\n");
      out.write("    else if (success === \"PunchIn\")\n");
      out.write("        showToast(\"Punched in successfully\");\n");
      out.write("\n");
      out.write("    else if (success === \"PunchOut\")\n");
      out.write("        showToast(\"Punched out successfully\");\n");
      out.write("\n");
      out.write("    else if (success === \"PerformanceSaved\")\n");
      out.write("        showToast(\"Performance submitted successfully\");\n");
      out.write("\n");
      out.write("    else if (success === \"true\")\n");
      out.write("        showToast(\"Task assigned successfully\");\n");
      out.write("\n");
      out.write("\n");
      out.write("    /* -------- ERROR MESSAGES -------- */\n");
      out.write("    if (error === \"SelectEmployee\")\n");
      out.write("        showToast(\"Please select an employee\", \"error\");\n");
      out.write("\n");
      out.write("    else if (error === \"InvalidEmployee\")\n");
      out.write("        showToast(\"You cannot assign task to this employee\", \"error\");\n");
      out.write("\n");
      out.write("    else if (error === \"EmptyTask\")\n");
      out.write("        showToast(\"Task description cannot be empty\", \"error\");\n");
      out.write("\n");
      out.write("    else if (error === \"AlreadyRated\")\n");
      out.write("        showToast(\"Performance already submitted for this employee this month\", \"error\");\n");
      out.write("\n");
      out.write("    else if (error === \"accessDenied\")\n");
      out.write("        showToast(\"Access denied. You do not have permission for that page.\", \"error\");\n");
      out.write("\n");
      out.write("    /* -------- Clean URL -------- */\n");
      out.write("    if (tab || success || error) {\n");
      out.write("        setTimeout(() => {\n");
      out.write("            window.history.replaceState({}, document.title, window.location.pathname);\n");
      out.write("        }, 100);\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    /* -------- Meeting Form AJAX -------- */\n");
      out.write("    const meetingForm = document.getElementById(\"meetingForm\");\n");
      out.write("\n");
      out.write("    if (meetingForm) {\n");
      out.write("        meetingForm.addEventListener(\"submit\", function (e) {\n");
      out.write("            e.preventDefault();\n");
      out.write("\n");
      out.write("            const formData = new FormData(meetingForm);\n");
      out.write("\n");
      out.write("            fetch(\"schedulemeeting\", {\n");
      out.write("                method: \"POST\",\n");
      out.write("                body: formData\n");
      out.write("            })\n");
      out.write("            .then(res => res.text())\n");
      out.write("            .then(text => {\n");
      out.write("                switch (text.trim()) {\n");
      out.write("                    case \"SUCCESS\":\n");
      out.write("                        showToast(\"Meeting scheduled successfully\");\n");
      out.write("                        meetingForm.reset();\n");
      out.write("                        break;\n");
      out.write("\n");
      out.write("                    case \"INVALID\":\n");
      out.write("                        showToast(\"Please fill all required fields\", \"error\");\n");
      out.write("                        break;\n");
      out.write("\n");
      out.write("                    case \"INVALID_TIME\":\n");
      out.write("                        showToast(\"End time must be after start time\", \"error\");\n");
      out.write("                        break;\n");
      out.write("\n");
      out.write("                    default:\n");
      out.write("                        showToast(\"Something went wrong\", \"error\");\n");
      out.write("                }\n");
      out.write("            })\n");
      out.write("            .catch(() => {\n");
      out.write("                showToast(\"Server error\", \"error\");\n");
      out.write("            });\n");
      out.write("        });\n");
      out.write("    }\n");
      out.write("\n");
      out.write("});\n");
      out.write("\n");
      out.write("/* ================= TOAST FUNCTION ================= */\n");
      out.write("function showToast(message, type = \"success\") {\n");
      out.write("    const toast = document.getElementById(\"toast\");\n");
      out.write("\n");
      out.write("    toast.style.display = \"none\";\n");
      out.write("    toast.className = \"toast\";\n");
      out.write("    toast.offsetHeight;\n");
      out.write("\n");
      out.write("    toast.classList.add(type);\n");
      out.write("    toast.textContent = message;\n");
      out.write("    toast.style.display = \"block\";\n");
      out.write("\n");
      out.write("    setTimeout(() => {\n");
      out.write("        toast.classList.add(\"hide\");\n");
      out.write("\n");
      out.write("        setTimeout(() => {\n");
      out.write("            toast.style.display = \"none\";\n");
      out.write("            toast.className = \"toast\";\n");
      out.write("        }, 400);\n");
      out.write("    }, 2500);\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* ================= UI FUNCTIONS ================= */\n");
      out.write("\n");
      out.write("function showSection(id) {\n");
      out.write("    document.querySelectorAll('.box').forEach(b => b.style.display = 'none');\n");
      out.write("    if (document.getElementById(id))\n");
      out.write("        document.getElementById(id).style.display = 'block';\n");
      out.write("}\n");
      out.write("\n");
      out.write("function toggleTheme() {\n");
      out.write("    document.body.classList.toggle(\"dark-theme\");\n");
      out.write("    localStorage.setItem(\"theme\",\n");
      out.write("        document.body.classList.contains(\"dark-theme\") ? \"dark\" : \"light\"\n");
      out.write("    );\n");
      out.write("}\n");
      out.write("\n");
      out.write("function openAllMeetings() {\n");
      out.write("    document.getElementById(\"allMeetingsModal\").classList.add(\"show\");\n");
      out.write("\n");
      out.write("    fetch(\"");
      out.print(request.getContextPath());
      out.write("/allMeetings\")\n");
      out.write("        .then(res => res.text())\n");
      out.write("        .then(html => {\n");
      out.write("            document.getElementById(\"allMeetingsContent\").innerHTML = html;\n");
      out.write("        })\n");
      out.write("        .catch(() => {\n");
      out.write("            document.getElementById(\"allMeetingsContent\").innerHTML =\n");
      out.write("                \"<p>Error loading meetings</p>\";\n");
      out.write("        });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function closeAllMeetings() {\n");
      out.write("    document.getElementById(\"allMeetingsModal\").classList.remove(\"show\");\n");
      out.write("}\n");
      out.write("\n");
      out.write("function openSettings(){ document.getElementById(\"settingsPanel\").classList.add(\"open\"); }\n");
      out.write("function closeSettings(){ document.getElementById(\"settingsPanel\").classList.remove(\"open\"); }\n");
      out.write("\n");
      out.write("function openProfile() {\n");
      out.write("    document.getElementById(\"profileModal\").style.visibility = \"visible\";\n");
      out.write("    document.getElementById(\"profileModal\").style.opacity = \"1\";\n");
      out.write("}\n");
      out.write("\n");
      out.write("function closeProfile() {\n");
