      out.write("    document.getElementById(\"profileModal\").style.opacity = \"0\";\n");
      out.write("}\n");
      out.write("\n");
      out.write("function openChangePassword(){\n");
      out.write("    document.getElementById(\"passwordModal\").classList.add(\"show\");\n");
      out.write("}\n");
      out.write("\n");
      out.write("function closeChangePassword(){\n");
