      out.write("}\n");
      out.write("\n");
      out.write("function closeAll(){\n");
      out.write("    closeSettings();\n");
      out.write("    closeProfile();\n");
      out.write("    closeChangePassword();\n");
      out.write("    closeAllMeetings();\n");
      out.write("}\n");
      out.write("\n");
      out.write("function submitPassword() {\n");
      out.write("    const newPassword = document.getElementById(\"newPassword\").value.trim();\n");
      out.write("    const confirmPassword = document.getElementById(\"confirmPassword\").value.trim();\n");
      out.write("\n");
      out.write("    if (!newPassword || !confirmPassword) {\n");
      out.write("        showToast(\"Please fill all fields\", \"error\");\n");
      out.write("        return;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    fetch(\"");
      out.print(request.getContextPath());
      out.write("/changePassword\", {\n");
      out.write("        method: \"POST\",\n");
      out.write("        headers: { \"Content-Type\": \"application/x-www-form-urlencoded\" },\n");
      out.write("        body: new URLSearchParams({\n");
      out.write("            newPassword: newPassword,\n");
      out.write("            confirmPassword: confirmPassword\n");
      out.write("        })\n");
      out.write("    })\n");
      out.write("    .then(res => res.text())\n");
      out.write("    .then(response => {\n");
      out.write("        switch (response.trim()) {\n");
      out.write("            case \"Success\":\n");
      out.write("                showToast(\"Password updated successfully\");\n");
      out.write("                closeChangePassword();\n");
      out.write("                document.getElementById(\"newPassword\").value = \"\";\n");
      out.write("                document.getElementById(\"confirmPassword\").value = \"\";\n");
      out.write("                break;\n");
      out.write("\n");
      out.write("            case \"PasswordMismatch\":\n");
      out.write("                showToast(\"Passwords do not match\", \"error\");\n");
      out.write("                break;\n");
      out.write("\n");
      out.write("            case \"MissingFields\":\n");
      out.write("                showToast(\"All fields are required\", \"error\");\n");
      out.write("                break;\n");
      out.write("\n");
      out.write("            case \"Unauthorized\":\n");
      out.write("                showToast(\"Session expired. Please login again\", \"error\");\n");
      out.write("                break;\n");
      out.write("\n");
      out.write("            default:\n");
      out.write("                showToast(\"Something went wrong\", \"error\");\n");
      out.write("        }\n");
      out.write("    })\n");
      out.write("    .catch(() => {\n");
      out.write("        showToast(\"Server error\", \"error\");\n");
      out.write("    });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function openCalendar() {\n");
      out.write("    document.querySelectorAll('.box').forEach(b => b.style.display = 'none');\n");
      out.write("    document.getElementById(\"calendarSection\").style.display = \"block\";\n");
      out.write("    document.getElementById(\"calendarFrame\").src =\n");
      out.write("        \"");
      out.print(request.getContextPath());
      out.write("/calendar.jsp\";\n");
      out.write("}\n");
      out.write("\n");
      out.write("function openNotifications() {\n");
      out.write("    document.getElementById(\"notificationPanel\").classList.add(\"show\");\n");
      out.write("}\n");
      out.write("\n");
      out.write("function closeNotifications() {\n");
      out.write("    document.getElementById(\"notificationPanel\").classList.remove(\"show\");\n");
      out.write("}\n");
      out.write("\n");
      out.write("function markAsRead(notificationId) {\n");
      out.write("    fetch(\"markNotificationRead?id=\" + notificationId, { method: \"POST\" })\n");
      out.write("        .then(response => {\n");
      out.write("            if (response.ok) {\n");
      out.write("                const el = document.getElementById(\"notif-\" + notificationId);\n");
      out.write("                if (el) el.remove();\n");
      out.write("\n");
      out.write("                const list = document.getElementById(\"notificationList\");\n");
      out.write("                const remaining = list.querySelectorAll(\".notification-item\");\n");
      out.write("\n");
      out.write("                if (remaining.length === 0) {\n");
      out.write("                    list.innerHTML = `\n");
      out.write("                        <div class=\"notification-item\">\n");
      out.write("                            No notifications\n");
      out.write("                        </div>\n");
      out.write("                    `;\n");
      out.write("                }\n");
      out.write("            }\n");
      out.write("        })\n");
      out.write("        .catch(err => console.error(err));\n");
      out.write("}\n");
      out.write("\n");
      out.write("function setActive(button) {\n");
